import React, { useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useLocation, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import * as yup from "yup";
import { useFormik } from "formik";
import { Button } from "antd";
import {
  Tag,
  Save,
  ArrowLeft,
  ChevronRight,
  Hash,
  ShieldCheck,
} from "lucide-react";
import {
  createTag,
  getTag,
  resetState,
  updateTag,
} from "../features/tags/tagsSlice";

let schema = yup.object().shape({
  title: yup.string().required("Tag Name is Required"),
});

const AddTag = () => {
  const dispatch = useDispatch();
  const location = useLocation();
  const getPCatId = location.pathname.split("/")[3];
  const navigate = useNavigate();
  const newCategory = useSelector((state) => state.tag);
  const { isSuccess, isError, isLoading, createdTag, tagName, updatedTag } =
    newCategory;

  useEffect(() => {
    if (getPCatId !== undefined) {
      dispatch(getTag(getPCatId));
    } else {
      dispatch(resetState());
    }
  }, [getPCatId]);

  useEffect(() => {
    if (isSuccess && createdTag) {
      toast.success("Tag Added Successfully!");
    }
    if (isSuccess && updatedTag) {
      toast.success("Tag Updated Successfully!");
      navigate("../list-tag");
    }
    if (isError) {
      toast.error("Something Went Wrong!");
    }
  }, [isSuccess, isError, isLoading]);

  const formik = useFormik({
    enableReinitialize: true,
    initialValues: {
      title: tagName || "",
      PostedByuserId: "",
    },
    validationSchema: schema,
    onSubmit: (values) => {
      if (getPCatId !== undefined) {
        const data = { id: getPCatId, pCatData: values };
        dispatch(updateTag(data));
        dispatch(resetState());
      } else {
        dispatch(createTag(values));
        toast.success("Tag has been added!");
        formik.resetForm();
        setTimeout(() => {
          dispatch(resetState());
        }, 1000);
      }
    },
  });

  useEffect(() => {
    const user = JSON.parse(localStorage.getItem("user"));
    if (user) {
      formik.setFieldValue("PostedByuserId", user._id || "");
    }
  }, []);

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-1000">
      {/* Header */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 bg-white/40 p-1 rounded-[32px] border border-white/60">
        <div className="pl-8 py-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-10 h-10 bg-[#257CB7] rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-500/20">
              <Hash size={20} />
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tighter">
              {getPCatId !== undefined ? "Update" : "Add"} Tag
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <span className="flex items-center gap-2 text-[10px] font-black text-blue-600 bg-blue-50 border border-blue-100 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
              <ShieldCheck size={12} /> Metadata Index
            </span>
          </div>
        </div>
        <div className="flex items-center gap-3 pr-4">
          <Button
            onClick={() => navigate(-1)}
            icon={<ArrowLeft size={16} />}
            className="rounded-2xl h-11 border-slate-200 text-slate-400 font-black text-[10px] uppercase tracking-widest"
          >
            Go Back
          </Button>
        </div>
      </div>

      {/* Form Card */}
      <div className="max-w-2xl">
        <div className="enterprise-card bg-white p-2 border-none shadow-2xl shadow-slate-200/40">
          <div className="flex items-center gap-4 px-10 py-8 border-b border-slate-50">
            <div className="p-3 bg-slate-50 rounded-2xl border border-slate-100">
              <Tag size={22} className="text-slate-400" />
            </div>
            <div>
              <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">
                Tag Details
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">
                Configure tag parameters
              </p>
            </div>
          </div>
          <form onSubmit={formik.handleSubmit} className="p-10 space-y-8">
            <div className="space-y-3">
              <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">
                <ChevronRight size={12} /> Tag Name
              </label>
              <input
                type="text"
                placeholder="Enter product tag"
                onChange={formik.handleChange("title")}
                onBlur={formik.handleBlur("title")}
                value={formik.values.title}
                className="w-full px-6 py-4 bg-slate-50/50 border border-slate-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-[#257CB7] focus:border-transparent transition-all duration-300 font-bold text-slate-900 placeholder-slate-300"
              />
              {formik.touched.title && formik.errors.title && (
                <p className="text-rose-500 text-[10px] uppercase font-black tracking-widest pl-4">
                  {formik.errors.title}
                </p>
              )}
            </div>
            <Button
              type="primary"
              htmlType="submit"
              loading={isLoading}
              size="large"
              icon={<Save size={16} />}
              className="bg-[#257CB7] rounded-2xl h-14 font-black text-[10px] uppercase tracking-widest shadow-xl shadow-blue-500/20 border-none hover:translate-y-[-2px] transition-all w-full flex items-center justify-center gap-3"
            >
              {getPCatId !== undefined ? "Update" : "Register"} Tag
            </Button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default AddTag;
